mapper.insert:
INSERT INTO TB_LMS_DSCS_CMNT (
      DSCS_CMNT_ID
    , DSCS_ATCL_ID
    , USER_ID
    , UP_CMNT_ID
    , CMNT_CTS
    , CMNT_CTS_LEN
    , RSPNS_REQYN
    , EMT_TYCD
    , DELYN
    , RGTR_ID
    , REG_DTTM
    , MDFR_ID
    , MOD_DTTM
) VALUES (
      #{dscsCmntId}
    , #{dscsAtclId}
    , #{rgtrId}
    , #{upCmntId}
    , #{cmntCts}
    , #{cmntCtsLen}
    , #{rspnsReqyn}
    , #{emtTycd}
    , 'N'
    , #{rgtrId}
    , FN_DTTM()
    , #{mdfrId}
    , FN_DTTM()
)

mapper.update:
UPDATE TB_LMS_DSCS_CMNT
SET CMNT_CTS = #{cmntCts}
  , CMNT_CTS_LEN = #{cmntCtsLen}
  , RSPNS_REQYN = #{rspnsReqyn}
  , MOD_DTTM = FN_DTTM()
  , MDFR_ID = #{mdfrId}
WHERE DSCS_CMNT_ID = #{dscsCmntId}

UPDATE TB_LMS_DSCS_CMNT
SET DELYN = 'Y'
  , MOD_DTTM = FN_DTTM()
  , MDFR_ID = #{mdfrId}
WHERE DSCS_CMNT_ID = #{dscsCmntId}

UPDATE TB_LMS_DSCS_CMNT
SET DELYN = 'H'
  , MOD_DTTM = FN_DTTM()
  , MDFR_ID = #{mdfrId}
WHERE DSCS_CMNT_ID = #{dscsCmntId}
